from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            return f"{subj} was {obj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Use lowercase for common status adjectives (e.g., retired)
            obj_clean = obj.strip().lower()
            # If the original object was capitalized and longer than one word, keep it as a proper noun (e.g., "NASA Astronaut")
            if obj and obj[0].isupper() and " " in obj:
                obj_clean = obj.strip()
            return f"{subj} is {obj_clean}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            # Convert minutes to hours/minutes if possible
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            # Subject is a mission/spacecraft; use passive voice
            return f"{subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Build special handling for mission‑crew relationships
    from collections import defaultdict
    mission_to_crew = defaultdict(list)          # mission -> list of crew members
    astronaut_to_mission = {}                    # astronaut -> mission
    used_triples = set()                         # triples consumed in combined sentences

    for t in triples:
        pred_key = t.predicate.lower().replace(" ", "")
        if pred_key == "crewmembers":
            mission_to_crew[t.subject].append(t.object)
            used_triples.add((t.subject, t.predicate, t.object))
        elif pred_key == "mission":
            astronaut_to_mission[t.subject] = t.object
            used_triples.add((t.subject, t.predicate, t.object))

    # Create combined sentences for each mission that has crew information
    combined_sentences = []
    for mission, crew_list in mission_to_crew.items():
        # add astronauts linked to this mission
        for astronaut, m in astronaut_to_mission.items():
            if m == mission:
                crew_list.append(astronaut)
        if crew_list:
            # preserve order while removing duplicates
            unique_names = list(dict.fromkeys(crew_list))
            if len(unique_names) == 1:
                sent = f"{unique_names[0]} was a crew member of {mission}"
            else:
                names_str = ", ".join(unique_names[:-1]) + " and " + unique_names[-1]
                sent = f"Both {names_str} were crew members aboard {mission}"
            combined_sentences.append(sent)

    # Filter out triples that have already been expressed in combined sentences
    remaining_triples = [t for t in triples if (t.subject, t.predicate, t.object) not in used_triples]

    # Group the remaining triples by subject as before
    groups = defaultdict(list)
    for t in remaining_triples:
        groups[t.subject].append(t)

    # Build sentences from the remaining groups
    for subj, items in groups.items():
        parts = [phrase(subj, t.predicate, t.object) for t in items]
        if len(parts) == 1:
            sent = parts[0]
        else:
            sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
        combined_sentences.append(sent)

    # Combine all sentences into a single fluent output
    return " Also, ".join(combined_sentences) + "."

# EVOLVE-BLOCK-END
